query GetTransactions($first: Int) {
  campaignOrderTransactionsWithEventsesConnection(first: $first) {
    edges {
      node {
        id
        orderId
        transactionDate
        revenue
        totalImpressions
        lastImpression
        attrMethod
        attrWindow
      }
    }
    aggregate {
      count
    }
    pageInfo {
      hasNextPage
      endCursor
    }
  }
}

query GetTransactionsByDate($first: Int, $startDate: DateTime!, $endDate: DateTime!) {
  campaignOrderTransactionsWithEventsesConnection(
    first: $first
    where: {
      transactionDate_gte: $startDate
      transactionDate_lte: $endDate
    }
  ) {
    edges {
      node {
        id
        orderId
        transactionDate
        revenue
        totalImpressions
        attrMethod
        attrWindow
      }
    }
    aggregate {
      count
    }
  }
}
